mapper.select:
select * from nx_distributer_father_goods where nx_dfg_distributer_id = #{disId}
and nx_dfg_father_goods_name like #{fathersFatherName}

    and nx_dfg_father_goods_level = #{fatherGoodsLevel}


    and nx_dfg_nx_goods_id = #{nxGoodsId}

select *
from nx_distributer_father_goods
where nx_dfg_nx_goods_id = #{nxGoodsId}
order by nx_dfg_father_goods_sort;

select * from nx_distributer_father_goods


        and nx_dfg_distributer_id = #{disId}


        and nx_dfg_nx_goods_id = #{nxGoodsId}

    and nx_dfg_father_goods_level = 1

select * from nx_distributer_father_goods


        nx_dfg_distributer_id = #{disId}


        and nx_dfg_fathers_father_id = #{fathersFatherId}



        and nx_dfg_father_goods_level = #{goodsLevel}


        and nx_dfg_father_goods_sort >= #{dayuSort}


        and nx_dfg_nx_goods_id = #{nxGoodsId}


        and nx_dfg_nx_goods_id is null

    order by nx_dfg_father_goods_sort

        limit #{offset}, #{limit}

select MAX(nx_dfg_father_goods_sort)
from nx_distributer_father_goods
where nx_dfg_fathers_father_id = #{fatherId}

select ndg.nx_distributer_goods_id ,ndg.nx_dg_dfg_goods_grand_id, ndg.nx_dg_purchase_auto, ndg.nx_dg_goods_name, father.nx_distributer_father_goods_id 'father_nx_distributer_father_goods_id', father.nx_dfg_fathers_father_id 'father_nx_dfg_fathers_father_id', father.nx_dfg_father_goods_name 'father_nx_dfg_father_goods_name', father.nx_dfg_goods_amount 'father_nx_dfg_goods_amount', father.nx_dfg_father_goods_color 'father_nx_dfg_father_goods_color', father.nx_dfg_nx_goods_id 'father_nx_dfg_nx_goods_id', father.nx_dfg_father_goods_img 'father_nx_dfg_father_goods_img', father.nx_dfg_father_goods_img_large 'father_nx_dfg_father_goods_img_large', father.nx_dfg_father_goods_sort 'father_nx_dfg_father_goods_sort', COALESCE(father_count.cnt, 0) AS 'father_goods_count', greatGrand.nx_distributer_father_goods_id 'greatGrand_nx_distributer_father_goods_id', greatGrand.nx_dfg_fathers_father_id 'greatGrand_nx_dfg_fathers_father_id', greatGrand.nx_dfg_father_goods_name 'greatGrand_nx_dfg_father_goods_name', greatGrand.nx_dfg_nx_goods_id 'greatGrand_nx_dfg_nx_goods_id', greatGrand.nx_dfg_father_goods_color 'greatGrand_nx_dfg_father_goods_color', greatGrand.nx_dfg_father_goods_img 'greatGrand_nx_dfg_father_goods_img', greatGrand.nx_dfg_father_goods_sort 'greatGrand_nx_dfg_father_goods_sort', COALESCE(greatGrand_count.cnt, 0) AS 'greatGrand_goods_count' from nx_distributer_father_goods as greatGrand left join nx_distributer_father_goods as father on father.nx_dfg_fathers_father_id = greatGrand.nx_distributer_father_goods_id inner join nx_distributer_goods as ndg on ndg.nx_dg_dfg_goods_grand_id = father.nx_distributer_father_goods_id and (
ndg.nx_dg_goods_is_hidden = #{isHidden}
ndg.nx_dg_goods_is_hidden = 0
) -- 优化：使用LEFT JOIN替代子查询计算father的商品数量 LEFT JOIN ( SELECT nx_dg_dfg_goods_grand_id, COUNT(DISTINCT nx_distributer_goods_id) AS cnt FROM nx_distributer_goods
AND nx_dg_goods_is_hidden = #{isHidden}
AND nx_dg_goods_is_hidden = 0
AND nx_dg_distributer_id in
#{id}
AND nx_dg_distributer_id = #{disId}
AND nx_dg_purchase_auto = #{goodsType}
AND nx_dg_supplier_id IS NOT NULL AND nx_dg_supplier_id > 0
AND nx_dg_carton_unit IS NOT NULL AND TRIM(nx_dg_carton_unit) != ''
AND (nx_dg_carton_unit IS NULL OR TRIM(nx_dg_carton_unit) = '')
AND nx_dg_items_per_carton IS NOT NULL AND TRIM(nx_dg_items_per_carton) != ''
AND (nx_dg_items_per_carton IS NULL OR TRIM(nx_dg_items_per_carton) = '')
AND nx_dg_trace_report_id IS NOT NULL
AND nx_dg_trace_report_id IS NULL
GROUP BY nx_dg_dfg_goods_grand_id ) AS father_count ON father_count.nx_dg_dfg_goods_grand_id = father.nx_distributer_father_goods_id -- 优化：使用LEFT JOIN替代子查询计算greatGrand的商品数量 LEFT JOIN ( SELECT COALESCE(father_count.nx_dfg_fathers_father_id, goods_count.nx_dg_nx_great_grand_id) AS great_grand_id, COUNT(DISTINCT goods_count.nx_distributer_goods_id) AS cnt FROM nx_distributer_goods AS goods_count LEFT JOIN nx_distributer_father_goods AS father_count ON goods_count.nx_dg_dfg_goods_grand_id = father_count.nx_distributer_father_goods_id
AND goods_count.nx_dg_goods_is_hidden = #{isHidden}
AND goods_count.nx_dg_goods_is_hidden = 0
AND (father_count.nx_dfg_fathers_father_id IS NOT NULL OR goods_count.nx_dg_nx_great_grand_id IS NOT NULL)
AND goods_count.nx_dg_distributer_id in
#{id}
AND goods_count.nx_dg_distributer_id = #{disId}
AND goods_count.nx_dg_purchase_auto = #{goodsType}
AND goods_count.nx_dg_supplier_id IS NOT NULL AND goods_count.nx_dg_supplier_id > 0
AND goods_count.nx_dg_carton_unit IS NOT NULL AND TRIM(goods_count.nx_dg_carton_unit) != ''
AND (goods_count.nx_dg_carton_unit IS NULL OR TRIM(goods_count.nx_dg_carton_unit) = '')
AND nx_dg_items_per_carton IS NOT NULL AND TRIM(nx_dg_items_per_carton) != ''
AND (nx_dg_items_per_carton IS NULL OR TRIM(nx_dg_items_per_carton) = '')
AND goods_count.nx_dg_trace_report_id IS NOT NULL
AND goods_count.nx_dg_trace_report_id IS NULL
GROUP BY COALESCE(father_count.nx_dfg_fathers_father_id, goods_count.nx_dg_nx_great_grand_id) ) AS greatGrand_count ON greatGrand_count.great_grand_id = greatGrand.nx_distributer_father_goods_id
and greatGrand.nx_dfg_distributer_id in
#{id}
and greatGrand.nx_dfg_father_goods_level = 0
and greatGrand.nx_dfg_distributer_id = #{disId} and greatGrand.nx_dfg_father_goods_level = 0
and ndg.nx_dg_distributer_id in
#{id}
and ndg.nx_dg_distributer_id = #{disId}
and ndg.nx_dg_purchase_auto = #{goodsType}
and ndg.nx_dg_supplier_id is not null and ndg.nx_dg_supplier_id > 0
and ndg.nx_dg_carton_unit is not null and TRIM(ndg.nx_dg_carton_unit) != ''
and (ndg.nx_dg_carton_unit is null or TRIM(ndg.nx_dg_carton_unit) = '')
AND nx_dg_items_per_carton IS NOT NULL AND TRIM(nx_dg_items_per_carton) != ''
AND (nx_dg_items_per_carton IS NULL OR TRIM(nx_dg_items_per_carton) = '')
and COALESCE(father_count.cnt, 0) > 0 and COALESCE(greatGrand_count.cnt, 0) > 0
and greatGrand.nx_dfg_nx_goods_id is not null order by greatGrand.nx_dfg_father_goods_sort, father.nx_dfg_father_goods_sort ;
